fun solve(code: Array<String>, businessLine: Array<String>, isActive: Array<Boolean>): Array<String> {
    val validCoupons = mutableListOf<String>()

    val validBusinessLines = setOf("electronics", "grocery", "pharmacy", "restaurant")
    val validCodePattern = Regex("^[a-zA-Z0-9_]+$")

    for (i in code.indices) {
        if (code[i].isEmpty()) continue
        if (!validCodePattern.matches(code[i])) continue
        if (!validBusinessLines.contains(businessLine[i])) continue
        if (!isActive[i]) continue

        validCoupons.add(code[i])
    }

    // Sort by businessLine order and then by code in lexicographical order
    validCoupons.sortWith(compareBy<String> { businessLine.indexOf(it) } { it })

    return validCoupons.toTypedArray()
}
